class RateLimiter {
  private timestamps: number[] = [];
  isAllowed(maxRequests: number, windowMs: number): boolean {
    const now = Date.now();
    this.timestamps = this.timestamps.filter(t => now - t < windowMs);
    if (this.timestamps.length >= maxRequests) return false;
    this.timestamps.push(now);
    return true;
  }
}

function getVisibleRange(scrollTop: number, itemHeight: number, viewportHeight: number, buffer: number) {
  const start = Math.max(0, Math.floor(scrollTop / itemHeight) - buffer);
  const end = Math.ceil((scrollTop + viewportHeight) / itemHeight) + buffer;
  return { start, end };
}

