// Fixed-size window: max sum of k consecutive elements
function maxSumWindow(arr: number[], k: number): number {
  let windowSum = arr.slice(0, k).reduce((a, b) => a + b, 0);
  let maxSum = windowSum;
  for (let i = k; i < arr.length; i++) {
    windowSum += arr[i] - arr[i - k]; // add new, remove old
    maxSum = Math.max(maxSum, windowSum);
  }
  return maxSum;
}

// Variable-size window: longest substring with at most k distinct chars
function longestWithKDistinct(s: string, k: number): number {
  const freq = new Map<string, number>();
  let left = 0, maxLen = 0;
  for (let right = 0; right < s.length; right++) {
    const ch = s[right];
    freq.set(ch, (freq.get(ch) ?? 0) + 1);
    while (freq.size > k) {
      const lch = s[left++];
      freq.set(lch, freq.get(lch)! - 1);
      if (freq.get(lch) === 0) freq.delete(lch);
    }
    maxLen = Math.max(maxLen, right - left + 1);
  }
  return maxLen;
}

