function minWindow(s: string, t: string): string {
  const need = new Map<string,number>();
  for (const c of t) need.set(c, (need.get(c)??0)+1);
  let have = 0, required = need.size;
  const window = new Map<string,number>();
  let left = 0, best = '';
  for (let right = 0; right < s.length; right++) {
    const c = s[right];
    window.set(c, (window.get(c)??0)+1);
    if (need.has(c) && window.get(c) === need.get(c)) have++;
    while (have === required) {
      const sub = s.slice(left, right+1);
      if (!best || sub.length < best.length) best = sub;
      const lc = s[left++];
      window.set(lc, window.get(lc)!-1);
      if (need.has(lc) && window.get(lc)! < need.get(lc)!) have--;
    }
  }
  return best;
}

class RateLimiter {
  private queue: number[] = [];
  constructor(private maxRequests: number, private windowMs: number) {}
  allow(timestamp: number): boolean {
    // Remove expired timestamps
    while (this.queue.length > 0 && timestamp - this.queue[0] >= this.windowMs) {
      this.queue.shift();
    }
    if (this.queue.length < this.maxRequests) {
      this.queue.push(timestamp);
      return true;
    }
    return false;
  }
}
